# Example: AI model license registry lookup
# Used alongside scanner for AI-specific licenses not in SPDX databases

AI_MODEL_LICENSE_REGISTRY = {
    "meta-llama/Meta-Llama-3-8B": {
        "license": "Llama 3 Community License",
        "tier": "review_required",
        "commercial_use": True,
        "commercial_restriction": "Prohibited for organizations with >700M MAU",
        "prohibited_uses": ["weapons", "illegal surveillance", "disinformation"],
        "derivative_naming_required": True,
        "legal_review_url": "https://internal.example.com/oss-review/llama-3",
        "approved_for": ["coding-assistant", "document-qa"],
        "requires_recheck_on_version_change": True,
    },
    "google/gemma-2-9b-it": {
        "license": "Gemma Terms of Use",
        "tier": "review_required",
        "commercial_use": True,
        "prohibited_uses_ref": "https://ai.google.dev/gemma/prohibited_use_policy",
        "legal_review_url": "https://internal.example.com/oss-review/gemma-2",
        "approved_for": ["internal-chat", "code-completion"],
        "requires_recheck_on_version_change": True,
    },
    "mistralai/Mistral-7B-Instruct-v0.3": {
        "license": "Apache-2.0",
        "tier": "approved",
        "commercial_use": True,
        "requires_recheck_on_version_change": True,
    },
}

def check_model_license(model_id: str) -> dict:
    entry = AI_MODEL_LICENSE_REGISTRY.get(model_id)
    if entry is None:
        return {
            "status": "unknown",
            "action": "manual_review_required",
            "message": f"Model {model_id} not in registry. Submit for Legal review before use.",
        }
    if entry["tier"] == "approved":
        return {"status": "approved", "action": "proceed"}
    if entry["tier"] == "review_required":
        return {
            "status": "review_required",
            "action": "obtain_legal_signoff",
            "legal_review_url": entry.get("legal_review_url"),
            "message": f"Obtain Legal sign-off at {entry.get('legal_review_url')}",
        }
    return {"status": "prohibited", "action": "blocked"}
